mapper.insert:
/* com.matjzing.mapper.AttachingFileMapper.insertAttachingFile */
INSERT INTO ATTACHING_FILE (
	  TARGET_CD /*타겟_코드*/
	, TARGET_SEQ /*타겟_시퀀스*/
	, FILE_ORIGINAL_NAME /*파일_원본_명*/
	, FILE_PATH /*파일_경로*/
	, FILE_SIZE /*파일_사이즈*/
	, FILE_EXTENSION_NAME /*파일_확장자_명*/
	, OPEN_FILE_YN /*공개_파일_여부*/
	, USE_YN /*사용_여부*/
	, REGISTER_SEQ /*등록자_시퀀스*/
	, REGISTER_IP /*등록자_아이피*/
	, REGISTRATION_DT /*등록_일시*/
	, UPDATER_SEQ /*수정자_시퀀스*/
	, UPDATER_IP /*수정자_아이피*/
	, UPDATE_DT /*수정_일시*/
) VALUES (
	  #{targetCd}
	, #{targetSeq}
	, #{fileOriginalName}
	, #{filePath}
	, #{fileSize}
	, #{fileExtensionName}
	, #{openFileYn}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

mapper.update:
		/* com.matjzing.mapper.AttachingFileMapper.deleteAttachingFile */
    	UPDATE ATTACHING_FILE SET
			  UPDATER_SEQ = #{updaterSeq}
			, UPDATE_DT = NOW(3)
			, USE_YN = FALSE
		WHERE
			ATTACHING_FILE_SEQ = #{attachingFileSeq}

/* com.matjzing.mapper.AttachingFileMapper.deactivateAttachingFileByTarget */
UPDATE ATTACHING_FILE SET
	  UPDATER_SEQ = #{updaterSeq}
	, UPDATE_DT = NOW(3)
	, USE_YN = FALSE
WHERE
	TARGET_CD = #{targetCd}
	AND TARGET_SEQ = #{targetSeq}
	AND USE_YN = TRUE

	AND ATTACHING_FILE_SEQ != #{attachingFileSeq}

mapper.select:
/* com.matjzing.mapper.AttachingFileMapper.getFileList */ SELECT ATTACHING_FILE_SEQ /*첨부파일_시퀀스*/ , FILE_ORIGINAL_NAME /*파일_원본_명*/
, TARGET_SEQ /*타겟_시퀀스*/ , CONCAT(#{fileUrlPrefix}, FILE_PATH) as FILE_PATH /*파일_경로*/
, CONCAT(#{fileUrlPrefix}, TARGET_SEQ) as TARGET_SEQ /*타겟_시퀀스*/ , FILE_PATH
, FILE_SIZE /*파일_사이즈*/ , FILE_EXTENSION_NAME /*파일_확장자_명*/ FROM ATTACHING_FILE WHERE USE_YN = TRUE AND TARGET_CD = #{targetCd} AND TARGET_SEQ = #{targetSeq}
